import * as React from 'react';
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import type { RenderResult } from '@testing-library/react';
import { CheckboxGroup } from './CheckboxGroup';

describe('CheckboxGroup accessible name', () => {
  it('derives the accessible name from the visible label', () => {
    const view: RenderResult = render(
      <CheckboxGroup
        label="Choose toppings"
        choices={[{ label: 'Cheese' }, { label: 'Tomatoes' }]}
      />
    );
    expect(screen.getByRole('group', { name: /choose toppings/i })).toBeInTheDocument();
    view.unmount();
  });

  it('uses ariaLabel when label is omitted', () => {
    const view: RenderResult = render(
      <CheckboxGroup
        ariaLabel="Select communication channels"
        choices={[{ label: 'Email' }, { label: 'SMS' }]}
      />
    );
    expect(
      screen.getByRole('group', { name: /select communication channels/i })
    ).toBeInTheDocument();
    view.unmount();
  });

  it('renders without label or ariaLabel without throwing', () => {
    const view: RenderResult = render(<CheckboxGroup choices={[{ label: 'A' }]} />);
    expect(screen.getByRole('group')).toBeInTheDocument();
    view.unmount();
  });
});

describe('CheckboxGroup aria-describedby wiring', () => {
  it('references hint when provided', () => {
    const view: RenderResult = render(
      <CheckboxGroup
        label="Newsletter"
        hint="Pick at least one option"
        choices={[{ label: 'Daily' }]}
      />
    );
    const fieldset = screen.getByRole('group', { name: /newsletter/i });
    const hint = screen.getByText('Pick at least one option');
    expect(fieldset).toHaveAttribute('aria-describedby', hint.id);
    view.unmount();
  });

  it('references error when provided', () => {
    const view: RenderResult = render(
      <CheckboxGroup
        label="Newsletter"
        error="Pick at least one option"
        choices={[{ label: 'Daily' }]}
      />
    );
    const fieldset = screen.getByRole('group', { name: /newsletter/i });
    const errorContainer = screen.getByText('Pick at least one option').parentElement as HTMLElement;
    expect(fieldset).toHaveAttribute('aria-describedby', errorContainer.id);
    view.unmount();
  });

  it('references both hint and error when both are provided', () => {
    const view: RenderResult = render(
      <CheckboxGroup
        label="Newsletter"
        hint="Pick at least one option"
        error="This field is required"
        choices={[{ label: 'Daily' }]}
      />
    );
    const fieldset = screen.getByRole('group', { name: /newsletter/i });
    const hint = screen.getByText('Pick at least one option');
    const errorContainer = screen.getByText('This field is required').parentElement as HTMLElement;
    expect(fieldset).toHaveAttribute('aria-describedby', `${hint.id} ${errorContainer.id}`);
    view.unmount();
  });
});

describe('CheckboxGroup choices interaction', () => {
  it('checks a choice when toggled on', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(
      <CheckboxGroup label="Notifications" choices={[{ label: 'Email' }]} />
    );
    const checkbox = screen.getByRole('checkbox', { name: 'Email' });
    await user.click(checkbox);
    expect(checkbox).toBeChecked();
    view.unmount();
  });

  it('unchecks a choice when toggled off', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(
      <CheckboxGroup label="Notifications" choices={[{ label: 'Email' }]} />
    );
    const checkbox = screen.getByRole('checkbox', { name: 'Email' });
    await user.click(checkbox);
    await user.click(checkbox);
    expect(checkbox).not.toBeChecked();
    view.unmount();
  });

  it('calls onCheckedChange with the updated values on check', async () => {
    const user = userEvent.setup();
    const handleChange = jest.fn();
    const view: RenderResult = render(
      <CheckboxGroup
        label="Notifications"
        choices={[{ label: 'Email' }]}
        onCheckedChange={handleChange}
      />
    );
    const checkbox = screen.getByRole('checkbox', { name: 'Email' });
    await user.click(checkbox);
    const lastCall = handleChange.mock.calls[handleChange.mock.calls.length - 1]?.[0];
    expect(lastCall).toEqual(['Email']);
    view.unmount();
  });

  it('calls onCheckedChange with the updated values on uncheck', async () => {
    const user = userEvent.setup();
    const handleChange = jest.fn();
    const view: RenderResult = render(
      <CheckboxGroup
        label="Notifications"
        choices={[{ label: 'Email' }]}
        onCheckedChange={handleChange}
      />
    );
    const checkbox = screen.getByRole('checkbox', { name: 'Email' });
    await user.click(checkbox);
    await user.click(checkbox);
    const lastCall = handleChange.mock.calls[handleChange.mock.calls.length - 1]?.[0];
    expect(lastCall).toEqual([]);
    view.unmount();
  });
});

describe('CheckboxGroup info popover', () => {
  it('reveals popover content when info trigger is clicked', async () => {
    const user = userEvent.setup();
    render(
      <CheckboxGroup
        label="Notifications"
        info="Additional info about notification delivery."
        choices={[{ label: 'Email' }]}
      />
    );
    const trigger = screen.getByRole('button', { name: 'More info' });
    await user.click(trigger);
    expect(
      await screen.findByText('Additional info about notification delivery.')
    ).toBeVisible();
  });

  it('marks the info icon as decorative', () => {
    render(
      <CheckboxGroup
        label="Notifications"
        info="More info"
        choices={[{ label: 'Email' }]}
      />
    );
    const trigger = screen.getByRole('button', { name: 'More info' });
    const icon = trigger.querySelector('svg');
    expect(icon).toHaveAttribute('aria-hidden', 'true');
  });
});

describe('CheckboxGroup error slot', () => {
  it('renders a decorative icon before the error text', () => {
    render(
      <CheckboxGroup
        label="Notifications"
        error="Select at least one option."
        choices={[{ label: 'Email' }]}
      />
    );
    const errorText = screen.getByText('Select at least one option.');
    const icon = errorText.parentElement?.querySelector('svg');
    expect(icon).toHaveAttribute('aria-hidden', 'true');
  });
});
